section.code:
{
  "$schema": "https://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/testing-with-assistive-technology.json",
  "type": "object",
  "required": [
    "__faion_header__",
    "tiers",
    "bug_report_format"
  ],
  "properties": {
    "__faion_header__": {
      "type": "object",
      "required": [
        "methodology",
        "version",
        "produces"
      ],
      "properties": {
        "methodology": {
          "const": "testing-with-assistive-technology"
        },
        "version": {
          "type": "string"
        },
        "produces": {
          "const": "config"
        }
      }
    },
    "tiers": {
      "type": "object",
      "required": [
        "automated_ci",
        "manual_release",
        "at_user_quarterly"
      ],
      "properties": {
        "automated_ci": {
          "type": "object",
          "required": [
            "tools",
            "fail_on_new_violations",
            "owner"
          ],
          "properties": {
            "tools": {
              "type": "array",
              "items": {
                "enum": [
                  "axe-core",
                  "pa11y",
                  "lighthouse",
                  "ibm-equal-access"
                ]
              },
              "minItems": 1
            },
            "fail_on_new_violations": {
              "type": "boolean",
              "const": true
            },
            "owner": {
              "type": "string"
            }
          }
        },
        "manual_release": {
          "type": "object",
          "required": [
            "screen_readers",
            "owner"
          ],
          "properties": {
            "screen_readers": {
              "type": "array",
              "items": {
                "enum": [
                  "voiceover",
                  "nvda",
                  "jaws",
                  "talkback",
                  "narrator"
                ]
              },
              "minItems": 2
            },
            "keyboard_only": {
              "type": "boolean",
              "const": true
            },
            "owner": {
              "type": "string"
            }
          }
        },
        "at_user_quarterly": {
          "type": "object",
          "required": [
            "partner",
            "users_per_quarter",
            "owner"
          ],
          "properties": {
            "partner": {
              "type": "string"
            },
            "users_per_quarter": {
              "type": "integer",
              "minimum": 1
            },
            "owner": {
              "type": "string"
            }
          }
        }
      }
    },
    "bug_report_format": {
      "type": "object",
      "required": [
        "wcag_sc",
        "repro",
        "apg_pattern",
        "scope"
      ],
      "properties": {
        "wcag_sc": {
          "type": "boolean",
          "const": true
        },
        "repro": {
          "type": "boolean",
          "const": true
        },
        "apg_pattern": {
          "type": "boolean",
          "const": true
        },
        "scope": {
          "type": "boolean",
          "const": true
        }
      }
    }
  }
}

example.code:
{
  "__faion_header__": {
    "methodology": "testing-with-assistive-technology",
    "version": "1.1.0",
    "produces": "config"
  },
  "tiers": {
    "automated_ci": {
      "tools": [
        "axe-core",
        "lighthouse"
      ],
      "fail_on_new_violations": true,
      "owner": "fe-team"
    },
    "manual_release": {
      "screen_readers": [
        "voiceover",
        "nvda"
      ],
      "keyboard_only": true,
      "owner": "qa-lead"
    },
    "at_user_quarterly": {
      "partner": "AbilityTech Research",
      "users_per_quarter": 2,
      "owner": "a11y-lead"
    }
  },
  "bug_report_format": {
    "wcag_sc": true,
    "repro": true,
    "apg_pattern": true,
    "scope": true
  }
}
